module signal_generator (
    input clk,
    input rst_n,
    output reg [4:0] wave
);

localparam UP_STATE = 2'b00;
localparam DOWN_STATE = 2'b01;

reg [1:0] state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= UP_STATE;
        wave <= 5'b0;
    end
    else begin
        case (state)
            UP_STATE: begin
                if (wave == 5'b11111) begin
                    state <= DOWN_STATE;
                end
                else begin
                    wave <= wave + 1;
                end
            end
            DOWN_STATE: begin
                if (wave == 5'b00000) begin
                    state <= UP_STATE;
                end
                else begin
                    wave <= wave - 1;
                end
            end
        endcase
    end
end

endmodule
